mapper.sql:
LEFT JOIN marine_forecasts mf ON mf.spot_id = s.id AND (#{targetDate} IS NULL OR mf.forecast_date = #{targetDate}) AND mf.id = ( SELECT mf2.id FROM marine_forecasts mf2 WHERE mf2.spot_id = s.id
AND mf2.forecast_date = #{targetDate}
ORDER BY mf2.forecast_date DESC, mf2.time_slot ASC, mf2.id ASC LIMIT 1 )

mapper.select:
SELECT s.id AS spotId, s.experience, s.name AS spotName, s.lat, s.lng, s.region, mf.forecast_date AS forecastDate, mf.time_slot AS timeSlot, mf.total_index AS totalIndex, s.post_count AS postCount, CASE WHEN fs.id IS NULL THEN FALSE ELSE TRUE END AS favorite, CAST(mf.metrics AS CHAR) AS metrics FROM spots s
LEFT JOIN favorite_spots fs ON fs.spot_id = s.id AND fs.user_id = #{userId} WHERE s.active = 1 AND s.experience = #{experience}
AND s.region = #{region}
AND s.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY s.post_count DESC, s.name ASC
ORDER BY POW(s.lat - #{userLat}, 2) + POW(s.lng - #{userLng}, 2), s.name ASC
ORDER BY CASE mf.total_index WHEN '매우좋음' THEN 5 WHEN '좋음' THEN 4 WHEN '보통' THEN 3 WHEN '나쁨' THEN 2 WHEN '매우나쁨' THEN 1 ELSE 0 END DESC, s.name ASC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM spots s
WHERE s.active = 1
	AND s.experience = #{experience}

	AND s.region = #{region}


	AND s.name LIKE CONCAT('%', #{keyword}, '%')

SELECT EXISTS (
	SELECT 1
	FROM spots
	WHERE id = #{spotId}
		AND active = 1
)

mapper.delete:
DELETE FROM favorite_spots
WHERE spot_id = #{spotId}
	AND user_id = #{userId}
